const cp = require('child_process');
const fs = require('fs');
const scanDir = '__DOCUMENTS_DIR__';
const projRoot = '__PROJECT_ROOT__';

try {
  const raw = cp.execSync('bash scripts/scan-projects.sh "' + scanDir + '" 2>&1', {cwd: projRoot, timeout: 60000, encoding: 'utf8'});
  const agents = raw.trim().split(String.fromCharCode(10)).filter(l => l.includes('|true|')).map(l => l.split('|')[0]);
  const issues = [];
  const versions = {};

  for (const name of agents) {
    const eco = scanDir + '/' + name + '/ecosystem.md';
    if (!fs.existsSync(eco)) {
      issues.push({project: name, issue: 'missing ecosystem.md'});
    } else {
      const c = fs.readFileSync(eco, 'utf8');
      if (c.includes('_[') || c.length < 200) issues.push({project: name, issue: 'ecosystem.md not filled'});
    }
    const mPath = scanDir + '/' + name + '/.template-manifest.json';
    if (fs.existsSync(mPath)) {
      try {
        const v = JSON.parse(fs.readFileSync(mPath, 'utf8')).template_version || 'unknown';
        if (!versions[v]) versions[v] = [];
        versions[v].push(name);
      } catch {}
    }
  }

  return [{json: {
    status: 'complete', total: agents.length, issues,
    template_versions: versions, version_mismatch: Object.keys(versions).length > 1,
    timestamp: new Date().toISOString()
  }}];
} catch(e) {
  return [{json: {status: 'error', error: (e.stderr || '') + e.message}}];
}
